import React from 'react';
import { motion } from 'framer-motion';
import './FloatingElements.css';

const FloatingElements = () => {
  const circles = [
    { size: 300, duration: 25, delay: 0, x: '10%', y: '20%' },
    { size: 200, duration: 20, delay: 2, x: '80%', y: '60%' },
    { size: 150, duration: 18, delay: 4, x: '70%', y: '10%' },
    { size: 250, duration: 22, delay: 1, x: '20%', y: '70%' },
    { size: 180, duration: 19, delay: 3, x: '50%', y: '40%' },
    { size: 120, duration: 16, delay: 5, x: '90%', y: '30%' }
  ];

  const lines = [
    { width: '2px', height: '200px', x: '15%', duration: 15, delay: 0 },
    { width: '1px', height: '150px', x: '45%', duration: 18, delay: 2 },
    { width: '2px', height: '180px', x: '75%', duration: 20, delay: 4 },
    { width: '1px', height: '120px', x: '85%', duration: 16, delay: 1 }
  ];

  return (
    <div className="floating-background">
      {/* Floating circles */}
      {circles.map((circle, index) => (
        <motion.div
          key={index}
          className="floating-circle"
          style={{
            width: circle.size,
            height: circle.size,
            left: circle.x,
            top: circle.y
          }}
          animate={{
            y: [0, -30, 0],
            x: [0, 20, 0],
            scale: [1, 1.1, 1],
            opacity: [0.03, 0.06, 0.03]
          }}
          transition={{
            duration: circle.duration,
            repeat: Infinity,
            ease: "easeInOut",
            delay: circle.delay
          }}
        />
      ))}
      
      {/* Floating vertical lines */}
      {lines.map((line, index) => (
        <motion.div
          key={`line-${index}`}
          className="floating-line"
          style={{
            width: line.width,
            height: line.height,
            left: line.x
          }}
          animate={{
            y: ['100vh', '-200px'],
            opacity: [0, 0.15, 0]
          }}
          transition={{
            duration: line.duration,
            repeat: Infinity,
            ease: "linear",
            delay: line.delay
          }}
        />
      ))}
      
      {/* Floating dots */}
      {[...Array(15)].map((_, index) => (
        <motion.div
          key={`dot-${index}`}
          className="floating-dot"
          style={{
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`
          }}
          animate={{
            y: [0, -50, 0],
            opacity: [0.1, 0.3, 0.1]
          }}
          transition={{
            duration: 10 + Math.random() * 10,
            repeat: Infinity,
            ease: "easeInOut",
            delay: Math.random() * 5
          }}
        />
      ))}
    </div>
  );
};

export default FloatingElements;
